module top_module(
    input [3:0] A, B,
    output reg [7:0] result  // Change here from wire to reg
);reg [7:0] temp;
reg [2:0] obf_i;

always @(*) begin
    temp = 0;
    for(obf_i = 0; obf_i < 4; obf_i = obf_i + 1) begin
        if(B[obf_i] == 1) begin
            temp = temp + (A << obf_i);
        end
    end
    result = temp; // This assignment is now valid
end

endmodule
